head.b:skin:
.search-post-title{
text-align:center;
margin:20px 0;
}

.search-post-title a{
display:block;
padding:22px;
background:#6a0dad;
color:#ffffff;
text-decoration:none;
font-size:1.6rem;
font-weight:700;
border-radius:20px;
transition:0.3s;
box-shadow:0 8px 20px rgba(0,0,0,0.3);
}

.search-post-title a:hover{
background:#9d4edd;
transform:translateY(-5px);
}

.label-post-title{
text-align:center;
margin:20px 0;
}

.label-post-title a{
display:block;
padding:20px;
background:#6a0dad;
color:#ffffff;
text-decoration:none;
font-size:1.5rem;
font-weight:700;
border-radius:18px;
transition:0.3s;
}

.label-post-title a:hover{
background:#9d4edd;
transform:translateY(-4px);
}
/* Related Posts */
.related-topics {
    margin-top: 40px;
    padding-top: 25px;
    border-top: 1px solid var(--border);
}

.related-topics h3 {
    font-family: 'Space Grotesk', sans-serif;
    font-size: 1.5rem;
    margin-bottom: 20px;
    color: var(--primary);
}

.related-posts-container {
    display: flex;
    flex-direction: column;
    gap: 14px;
}

.related-post-item a {
    display: block;
    padding: 16px 20px;
    background: var(--bg-surface);
    border: 1px solid var(--border);
    border-radius: var(--radius-md);
    text-decoration: none;
    color: #ffffff;
    font-weight: 600;
    transition: var(--transition);
}

.related-post-item a:hover {
    background: var(--primary);
    border-color: var(--primary);
    transform: translateY(-4px);
}

/* Related Posts Slider */
.related-topics{
margin-top:50px;
padding-top:30px;
border-top:1px solid var(--border);
overflow:hidden;
}

.related-topics h3{
font-size:1.6rem;
margin-bottom:22px;
font-family:'Space Grotesk',sans-serif;
color:var(--primary);
}

.related-slider-wrap{
overflow:hidden;
width:100%;
position:relative;
}

.related-slider{
display:flex;
gap:20px;
width:max-content;
animation:relatedScroll 20s linear infinite alternate;
}

.related-card{
min-width:260px;
max-width:260px;
flex-shrink:0;
}

.related-card a{
display:flex;
align-items:center;
justify-content:center;
height:50px;
padding:20px;
background:var(--bg-surface);
border:0px solid var(--border);
border-radius:20px;
text-decoration:none;
color:#ffffff;
font-weight:700;
font-size:1rem;
text-align:center;
transition:var(--transition);
box-shadow:var(--shadow-card);

}

.related-card a:hover{
background:var(--primary);
transform:translateY(-6px);
border-color:var(--primary);
}

@keyframes relatedScroll{

0%{
transform:translateX(0%);
}

100%{
transform:translateX(-50%);
}

}

@media(max-width:768px){

.related-card{
min-width:220px;
max-width:220px;
}

.related-card a{
height:100px;
font-size:.95rem;
padding:16px;
}

}

