    /* ==========================================================================
       SlangBase Neo-Brutalist Fun Theme
       ========================================================================== */
    :root {
        --primary: #9d4edd;      /* Electric Neon Purple */
        --primary-accent: #ffc552; /* Soft Pastel Purple Accent */
        --neon-green: #ffc552;   /* Pop Highlight Color */

        --text-main: #ffffff;    /* Bright white text for contrast */
        --text-muted: #a3a3a3;   /* Light gray description text */
        --text-ghost: #525252;   /* Darker structural text */

        --bg-body: #000000;      /* Deep Midnight Black Body */
        --bg-card: #000000;      /* Dark Anthracite Card Background */
        --bg-surface: #000000;   /* Inner-element Gray Container */

        --border: #2f353c;       /* Clean Dark Border Line */
        --border-active: #9d4edd; /* Focused Active Border Line */

        --radius-sm: 10px;
        --radius-md: 18px;
        --radius-lg: 32px;
        --radius-full: 9999px;

        /* Distinctive Shadow Style for Startup Energy */
        --shadow-neon: 0px 8px 0px rgba(157, 78, 221, 0.15);
        --shadow-card: 0px 12px 24px rgba(0, 0, 0, 0.4);
        --transition: all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
    }

    * { 
        box-sizing: border-box; 
        margin: 0; 
        padding: 0; 
    }

    body {
        font-family: 'Plus Jakarta Sans', sans-serif;
        background-color: var(--bg-body);
        color: var(--text-main);
        line-height: 1.65;
        -webkit-font-smoothing: antialiased;
    }

    /* Header Design & Startup Title */
    .dict-header {
        background: linear-gradient(180deg, #11091c 0%, var(--bg-body) 100%);
        padding: 80px 24px 56px;
        text-align: center;
        border-bottom: 1px solid var(--border);
        position: relative;
    }



    .dict-title {
        font-family: 'Space Grotesk', sans-serif;
        font-size: 3.8rem;
        font-weight: 700;
        margin-bottom: 24px;
        letter-spacing: -0.03em;
    }

    .dict-title a { 
        text-decoration: none; 
        color: inherit;
        background: linear-gradient(135deg, #ffffff 40%, var(--primary) 100%);
        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
    }

    .search-container {
        max-width: 620px;
        margin: 0 auto;
        position: relative;
    }

    .search-container input {
        width: 100%;
        padding: 18px 32px;
        font-size: 1.1rem;
        font-family: inherit;
        color: var(--text-main);
        background-color: var(--bg-card);
        border: 2px solid var(--border);
        border-radius: var(--radius-full);
        outline: none;
        transition: var(--transition);
        box-shadow: var(--shadow-card);
    }

    .search-container input::placeholder {
        color: rgba(255, 255, 255, 0.35);
    }

    .search-container input:focus {
        border-color: var(--primary);
        box-shadow: 0 0 0 5px rgba(157, 78, 221, 0.25), var(--shadow-card);
        transform: scale(1.01);
    }

    /* Bold A-Z Filter Bar Grid */
    .az-nav {
        max-width: 960px;
        margin: 48px auto 24px;
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(42px, 1fr));
        gap: 8px;
        padding: 0 24px;
    }

    .az-nav a {
        display: flex;
        align-items: center;
        justify-content: center;
        height: 42px;
        background: var(--bg-card);
        border: 1px solid var(--border);
        border-radius: var(--radius-sm);
        text-decoration: none;
        color: var(--text-muted);
        font-family: 'Space Grotesk', sans-serif;
        font-weight: 500;
        font-size: 1rem;
        transition: var(--transition);
    }

    .az-nav a:hover {
        background: var(--primary);
        color: #ffffff;
        border-color: var(--primary);
        transform: translateY(-4px);
        box-shadow: 0 6px 14px rgba(157, 78, 221, 0.4);
    }

    /* Primary Container Area */
    .dict-container {
        max-width: 800px;
        margin: 24px auto 96px;
        padding: 0 24px;
    }

    /* Monetization Content Slot Wrapper */
    .widget-content {
        background: rgba(157, 78, 221, 0.05);
        border: 1px dashed rgba(157, 78, 221, 0.3);
        padding: 16px;
        border-radius: var(--radius-md);
        margin-bottom: 32px;
        text-align: center;
    }

    /* Neon Accent Word Post Entry Cards */
    .dict-entry {
    background: #ffffff; /* Purple */
        padding: 48px;
        border-radius: var(--radius-md);
        box-shadow: var(--shadow-card);
        margin-bottom: 36px;
        border: 1px solid var(--border);
        position: relative;
        overflow: hidden;
        transition: var(--transition);
    }

    .dict-entry::after {
        content: '';
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: 4px;
        background: linear-gradient(90deg, transparent, var(--primary), transparent);
        opacity: 0.7;
    }

    .dict-entry:hover {
        transform: translateY(-6px) scale(1.005);
        border-color: rgba(157, 78, 221, 0.4);
        box-shadow: 0 20px 38px rgba(0, 0, 0, 0.6), var(--shadow-neon);
    }

    .entry-header {
        margin-bottom: 28px;
        border-bottom: 1px solid var(--border);
        padding-bottom: 24px;
    }

    .word-title {
        font-family: 'Space Grotesk', sans-serif;
        font-size: 2.8rem;
        font-weight: 700;
        margin-bottom: 14px;
        letter-spacing: -0.02em;
        line-height: 1.2;
    }

    .word-title a { 
        text-decoration: none; 
        color: #000000; 
        transition: color 0.2s ease;
    }

    .word-title a:hover { 
        color: var(--primary); 
    }

    .word-meta {
        display: flex;
        align-items: center;
        flex-wrap: wrap;
        gap: 10px;
    }

    .pos-badge {
        background: rgba(157, 78, 221, 0.12);
        color: var(--primary-accent);
        padding: 6px 16px;
        border-radius: var(--radius-full);
        font-size: 0.75rem;
        font-weight: 700;
        text-transform: uppercase;
        letter-spacing: 0.08em;
        border: 1px solid rgba(157, 78, 221, 0.25);
    }

    /* Definition Text Area */
    .entry-content { 
        font-size: 1.15rem; 
        color: #000000; 
    }

    .phonetic-text {
        font-family: 'Space Grotesk', sans-serif;
        color: var(--neon-green);
        font-size: 1.1rem;
        margin-bottom: 20px;
        display: block;
        letter-spacing: 0.02em;
    }

    .entry-content ol, .entry-content ul {
        margin-left: 24px;
        margin-top: 16px;
    }

    .entry-content li { 
        margin-bottom: 18px; 
        padding-left: 6px; 
    }

    /* Contextual Fun Examples UI Block */
    .example-sentence {
        display: block;
        margin-top: 16px;
        padding: 20px 24px;
        border-left: 4px solid var(--primary);
        color: var(--text-muted);
        font-style: italic;
        font-size: 1.05rem;
        background: var(--bg-surface);
        border-radius: 0 var(--radius-sm) var(--radius-sm) 0;
    }

    /* Dynamic Pagination */
    .blog-pager {
        display: flex;
        justify-content: space-between;
        align-items: center;
        margin-top: 64px;
        padding-top: 40px;
        border-top: 1px solid var(--border);
    }

    .blog-pager a {
        padding: 14px 28px;
        background: var(--bg-card);
        border: 1px solid var(--border);
        border-radius: var(--radius-full);
        text-decoration: none;
        color: var(--text-main);
        font-family: 'Space Grotesk', sans-serif;
        font-weight: 500;
        font-size: 0.95rem;
        transition: var(--transition);
    }

    .blog-pager a:hover { 
        background: var(--bg-surface);
        border-color: var(--primary);
        transform: scale(1.05);
    }

    /* Dashboard Footer Struct */
    .dict-footer {
        text-align: center;
        padding: 56px 24px;
        color: var(--text-ghost);
        background: #060506;
        border-top: 1px solid var(--border);
        font-size: 0.9rem;
        letter-spacing: 0.02em;
    }

    /* Snappy Responsive Code */
    @media (max-width: 640px) {
        .dict-header { padding: 64px 16px 40px; }
        .dict-title { font-size: 2.6rem; margin-bottom: 20px; }
        .search-container input { padding: 16px 24px; font-size: 1rem; }
        .az-nav { grid-template-columns: repeat(7, 1fr); gap: 6px; padding: 0 16px; }
        .az-nav a { height: 38px; font-size: 0.9rem; }
        .dict-container { padding: 0 16px; margin-bottom: 64px; }
        .dict-entry { padding: 28px 24px; border-radius: var(--radius-sm); }
        .word-title { font-size: 2.1rem; }
    }
/* Popular Posts Links */
