#PopularPosts1 .widget-title,
#PopularPosts1 h2 {
    color: #ffffff !important; /* Change color here */
}

/* Related Topics Section */
.related-topics {
    margin-top: 40px;
    padding-top: 25px;
    border-top: 1px solid var(--border);
}

.related-topics h3 {
    font-family: 'Space Grotesk', sans-serif;
    font-size: 1.4rem;
    margin-bottom: 18px;
    color: var(--primary);
}

.related-topics ul {
    list-style: none;
    padding: 0;
    margin: 0;
}

.related-topics li {
    margin-bottom: 12px;
}

.related-topics a {
    display: inline-block;
    padding: 10px 18px;
    background: var(--bg-surface);
    border: 1px solid var(--border);
    border-radius: var(--radius-full);
    text-decoration: none;
    color: #ffffff;
    transition: var(--transition);
    font-weight: 600;
}

.related-topics a:hover {
    background: var(--primary);
    border-color: var(--primary);
    transform: translateY(-3px);
}

div.script:
//
var relatedTitles = [];
var relatedUrls = [];

function related_results(json) {

for (var i = 0; i < json.feed.entry.length; i++) {

var entry = json.feed.entry[i];

var posttitle = entry.title.$t;

var posturl;

for (var j = 0; j < entry.link.length; j++) {

if (entry.link[j].rel == 'alternate') {
posturl = entry.link[j].href;
break;
}

}

if (posturl != location.href) {

relatedTitles.push(posttitle);
relatedUrls.push(posturl);

}

}

var output = '';

for (var k = 0; k < relatedTitles.length && k < 5; k++) {

output += '<div class="related-card">';
output += '<a href="' + relatedUrls[k] + '">';
output += relatedTitles[k];
output += '</a>';
output += '</div>';

}

document.getElementById('related-slider').innerHTML = output + output;

}
//
